export async function createOrReuseOpenPullRequest(
	input: {
		owner: string;
		repository: string;
		head: string;
		base: string;
		title: string;
		body: string;
	},
	env: RhapsodyGitHubEnv = loadRhapsodyGitHubEnv(),
): Promise<PullRequestSummary> {
	const existing = await findOpenPullRequestForHead({
		env,
		owner: input.owner,
		repository: input.repository,
		head: input.head,
		base: input.base,
	});

	if (existing) {
		return {
			reused: true,
			...existing,
		};
	}

	let created: Awaited<ReturnType<typeof createPullRequest>>;
	try {
		created = await createPullRequest({
			env,
			owner: input.owner,
			repository: input.repository,
			title: input.title,
			body: input.body,
			head: input.head,
			base: input.base,
		});
	} catch (error) {
		if (
			!(error instanceof GitHubPullRequestError) ||
			![409, 422].includes(error.status)
		) {
			throw error;
		}

		const racedExisting = await findOpenPullRequestForHead({
			env,
			owner: input.owner,
			repository: input.repository,
			head: input.head,
			base: input.base,
		});

		if (racedExisting) {
			return {
				reused: true,
				...racedExisting,
			};
		}

		throw error;
	}

	return {
		reused: false,
		...created,
	};
}

async function findOpenPullRequestForHead({
	env,
	owner,
	repository,
	head,
	base,
}: {
	env: RhapsodyGitHubEnv;
	owner: string;
	repository: string;
	head: string;
	base: string;
}): Promise<{
	number: number;
	htmlUrl: string;
	title: string;
	headRef: string;
	baseRef: string;
} | null> {
	const response = await fetch(
		`https://api.github.com/repos/${encodeURIComponent(owner)}/${encodeURIComponent(
			repository,
		)}/pulls?state=open&head=${encodeURIComponent(`${owner}:${head}`)}`,
		{
			headers: {
				Accept: "application/vnd.github+json",
				Authorization: `Bearer ${env.GITHUB_TOKEN}`,
				"X-GitHub-Api-Version": "2022-11-28",
			},
		},
	);

	if (!response.ok) {
		const message = await safeResponseText(response);
		throw new GitHubPullRequestError(
			response.status,
			owner,
			repository,
			"lookup",
			message,
		);
	}

	const pulls = normalizePullRequestList(await response.json());

	if (pulls.length === 0) {
		return null;
	}

	const candidate = pulls.find((pull) => pull.base.ref === base);

	if (!candidate) {
		return null;
	}

	return {
		number: candidate.number,
		htmlUrl: candidate.html_url,
		title: candidate.title,
		headRef: candidate.head.ref,
		baseRef: candidate.base.ref,
	};
}

async function createPullRequest(args: {
	env: RhapsodyGitHubEnv;
	owner: string;
	repository: string;
	title: string;
	body: string;
	head: string;
	base: string;
}): Promise<{
	number: number;
	htmlUrl: string;
	title: string;
	headRef: string;
	baseRef: string;
}> {
	const response = await fetch(
		`https://api.github.com/repos/${encodeURIComponent(args.owner)}/${encodeURIComponent(args.repository)}/pulls`,
		{
			method: "POST",
			headers: {
				Accept: "application/vnd.github+json",
				Authorization: `Bearer ${args.env.GITHUB_TOKEN}`,
				"X-GitHub-Api-Version": "2022-11-28",
				"content-type": "application/json",
			},
			body: JSON.stringify({
				title: args.title,
				body: args.body,
				head: args.head,
				base: args.base,
			}),
		},
	);

	if (!response.ok) {
		const message = await safeResponseText(response);
		throw new GitHubPullRequestError(
			response.status,
			args.owner,
			args.repository,
			"create",
			message,
		);
	}

	const created = normalizePullRequest(await response.json());
	return {
		number: created.number,
		htmlUrl: created.html_url,
		title: created.title,
		headRef: created.head.ref,
		baseRef: created.base.ref,
	};
