+	return [
+		{
+			issueNumber,
+			issueTitle,
+			issueUrl,
+			issueState,
+			issueBody,
+			projectStatus,
+			repository: {
+				owner: repositoryOwner,
+				name: repositoryName,
+			},
+		},
+	];
+}
+
+function extractProjectStatus(
+	values: GitHubProjectItemFieldValueNode[] | null | undefined,
+	statusField: string,
+): string | null {
+	if (!Array.isArray(values)) {
+		return null;
+	}
