+		const valueField = safeString(value.field.name);
+		if (!valueField || valueField !== targetField) {
+			continue;
+		}
+
+		if (value.__typename === "ProjectV2ItemFieldSingleSelectValue") {
+			const status = safeString(value.name);
+			if (status) {
+				return status;
+			}
